const items = $input.all();
return items.map(item => {
    // Soporta 'id' o 'Variables' (el encabezado en la imagen del usuario)
    const encontrado = (item.json.id !== undefined) || (item.json.Variables !== undefined);
    return {
        json: {
            ...item.json,
            validaciones: {
                afectadoValidado: encontrado,
                timestamp: new Date().toISOString()
            }
        },
        binary: item.binary
    };
});

const items = $input.all();
return items.map(item => {
    return {
        json: {
            ...item.json,
            ocr_data: {
                proveedor: "Farmacia Guadalajara",
                monto: "1,250.00",
                fecha: "2024-03-10",
                montoNumerico: 1250,
                confidence: 0.98
            }
        },
        binary: item.binary
    };
});

const items = $input.all();
return items.map(item => {
    const ocr = item.json.ocr_data;
    const isValid = ocr && ocr.montoNumerico > 0;

    return {
        json: {
            ...item.json,
            validaciones: {
                ...item.json.validaciones,
                ocrValido: isValid
            }
        },
        binary: item.binary
    };
});

const items = $input.all();
return items.map(item => {
    return {
        json: {
            ...item.json,
            pdf_metadata: {
                nombreArchivo: `Reclamacion_${(item.json.afectado && item.json.afectado.nombre ? item.json.afectado.nombre.replace(/\s+/g, '_') : 'SinNombre')}.pdf`,
                fechaGeneracion: new Date().toISOString()
            }
        },
        binary: item.binary
    };
});

const items = $input.all();
return items.map(item => {
    const hasDocuments = item.binary && Object.keys(item.binary).length > 0;

    return {
        json: {
            ...item.json,
            checklist_final: {
                completado: hasDocuments,
                total_archivos: hasDocuments ? Object.keys(item.binary).length : 0
            }
        },
        binary: item.binary
    };
});

const items = $input.all();
return items.map(item => {
    return {
        json: {
            ...item.json,
            drive: {
                id: item.json.id,
                webViewLink: item.json.webViewLink,
                downloadLink: item.json.webContentLink
            }
        },
        binary: item.binary
    };
});

const item = $input.item.json;
const evento = (item.evento || 'reembolso').toLowerCase();

let subject = '';
const fecha = new Date().toLocaleDateString('es-MX');

const templateReembolso = `<h3>Solicitud de Reembolso</h3><p>Se adjunta expediente completo.</p>`; 
const templateMedicamentos = `<h3>Solicitud de Medicamentos</h3><p>Se adjunta expediente completo.</p>`;

let html = evento.includes('reembolso') ? templateReembolso : templateMedicamentos;
subject = (evento.includes('reembolso') ? '🏛️ METLIFE: Solicitud de Reembolso - ' : '🏛️ METLIFE: Solicitud de Medicamentos/Carta Pase - ') + (item.afectado && item.afectado.nombre ? item.afectado.nombre : 'Gestión SGMM');

return [{
    json: {
        ...item,
        metlife_subject: subject,
        metlife_html: html
    },
    binary: $input.item.binary
}];

const item = $input.item.json;
const binaryData = {};

if (item.documentoBase64) {
    binaryData['form_generado'] = {
        data: item.documentoBase64,
        fileName: (item.metadata && item.metadata.nombreArchivoGenerado ? item.metadata.nombreArchivoGenerado : 'Formato-GMM') + '.pdf',
        mimeType: 'application/pdf'
    };
}

if (item.archivosManuales && Array.isArray(item.archivosManuales)) {
    item.archivosManuales.forEach((file, index) => {
        binaryData[`attach_${index}`] = {
            data: file.base64,
            fileName: file.name,
            mimeType: file.type || 'application/octet-stream'
        };
    });
}

return {
    json: item,
    binary: binaryData
};
